<template>
    <div style="margin:45px;height: 80%">
      <div>
        
        <n-space justify="center">
            <n-tag size="large"> 请选择时间区间 </n-tag>
            
            <n-select  v-model:value="data_description" style="width:200px;" :options="data_options" />
            <n-button type="Primary" @click="getPressureFaultDiagnosisData">查询</n-button>
            
        </n-space>
    </div>
    <div ref="charts" style="margin-left:10%;height:80%;width:80%"></div>
    </div>
    </template>

<script setup>
import { NDatePicker } from "naive-ui";
import * as echarts from 'echarts';
import 'echarts-gl';
import { onMounted, ref } from 'vue-demi';
import dayjs from "dayjs";
import { getPressureFaultDiagnosis,getSupportNum } from "@/api/request";
import $ from 'jquery';

//获取时间数据value
let endTime = Date.now();
let startTime = endTime - 24 * 60 * 60 * 1000 ;
const range = ref([startTime, endTime]);
const charts = ref(null);
const pressurefaultdiagnosisdata = ref(null);

let data_description = ref(0);
let data_options = ref([{"label":dayjs(endTime).format("YYYY-MM-DD"),"value":0},{"label":dayjs(endTime- 24 * 60 * 60 * 1000).format("YYYY-MM-DD"),"value":1},{"label":dayjs(endTime- 2*24 * 60 * 60 * 1000).format("YYYY-MM-DD"),"value":2},{"label":dayjs(endTime- 3*24 * 60 * 60 * 1000).format("YYYY-MM-DD"),"value":3},{"label":dayjs(endTime- 4*24 * 60 * 60 * 1000).format("YYYY-MM-DD"),"value":4}]);
let res
onMounted(async () => {
    res = await getSupportNum();
});

const getPressureFaultDiagnosisData = async () => {
   console.log("触发查询请求",res.message)
    let option;

    let { code, message } = await getPressureFaultDiagnosis({
      days:data_description.value
     });
    pressurefaultdiagnosisdata.value = message;
    
    let  result = [];
    for(var i=0;i<res.message;i++){
        result.push({product:(i+1).toString()+'号支架','压力过高':pressurefaultdiagnosisdata.value[i].high_alarm_times,'压力过低':pressurefaultdiagnosisdata.value[i].low_alarm_times})
    }    
    console.log("pressurefaultdiagnosisdata",result )

    let chartDom = echarts.init(charts.value)
    //let data = message
    chartDom.setOption(
    (option = {
        
    legend: {},
    tooltip:{},
    dataset:{
    dimensions: ['product', '压力过高', '压力过低'],
    source: result
  },
  xAxis: { type: 'category' },
  yAxis: {},
  // Declare several bar series, each will be mapped
  // to a column of dataset.source by default.
  series: [{ type: 'bar' }, { type: 'bar' }]
    }
  )
);
option && chartDom.setOption(option);

}

</script>